import{c as a,Q as n,j as t,m as i}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"信息搜集与侦察:OSINT / 子域名 / 端口扫描 / 指纹识别","description":"","frontmatter":{},"headers":[],"relativePath":"securityLearning/21-信息搜集与侦察.md","filePath":"securityLearning/21-信息搜集与侦察.md","lastUpdated":1778496697000}'),e={name:"securityLearning/21-信息搜集与侦察.md"};function p(o,s,l,r,h,d){return n(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="信息搜集与侦察-osint-子域名-端口扫描-指纹识别" tabindex="-1">信息搜集与侦察:OSINT / 子域名 / 端口扫描 / 指纹识别 <a class="header-anchor" href="#信息搜集与侦察-osint-子域名-端口扫描-指纹识别" aria-label="Permalink to &quot;信息搜集与侦察:OSINT / 子域名 / 端口扫描 / 指纹识别&quot;">​</a></h1><p>从这一篇开始进入第五层——<strong>渗透与攻防实战</strong>。但在讲怎么打之前必须先讲一件事:<strong>真实攻击者花在「踩点」上的时间,远超花在「利用漏洞」上</strong>。红队报告里写「48 小时拿到域控」,前 36 小时基本都在做侦察——梳理资产、扫端口、找指纹、翻 GitHub。<strong>这恰恰是防御方最容易忽略的阶段</strong>——日志里看不见,WAF 拦不住,SOC 报警不响。攻击者已经把你的整个外部攻击面摸了三遍,你的安全团队还不知道有人在看。这一篇从攻击者侧入手,讲清四件事:<strong>OSINT、子域名、端口扫描、指纹识别</strong>;然后反推防御方该堵什么——外部攻击面管理(EASM)和「把自己当攻击者扫一遍」的常态化。</p><blockquote><p>一句话先记住:<strong>侦察阶段攻击者只是在「读」你的资产,但你 95% 的安全事故,根因都是「有个你不知道存在的东西暴露在公网上」</strong>——一个测试环境忘了关、一个子公司域名没清单、一个员工把 AWS key 推到了 GitHub。防御侦察 ≠ 阻止扫描(挡不住),<strong>而是先于攻击者把自己摸一遍</strong>——让外部攻击面比你以为的更小、更清楚。这一篇的核心心智不是「学几个工具」,是**「资产清单 = 安全的地基,清单不准,后面一切防御都是空的」**。</p></blockquote><hr><h2 id="一、为什么侦察是攻击者最看重、防御方最忽略的一步" tabindex="-1">一、为什么侦察是攻击者最看重、防御方最忽略的一步 <a class="header-anchor" href="#一、为什么侦察是攻击者最看重、防御方最忽略的一步" aria-label="Permalink to &quot;一、为什么侦察是攻击者最看重、防御方最忽略的一步&quot;">​</a></h2><h3 id="_1-1-渗透杀链里侦察的位置" tabindex="-1">1.1 渗透杀链里侦察的位置 <a class="header-anchor" href="#_1-1-渗透杀链里侦察的位置" aria-label="Permalink to &quot;1.1 渗透杀链里侦察的位置&quot;">​</a></h3><p>Lockheed Martin 的 Cyber Kill Chain 七步:<code>Reconnaissance → Weaponization → Delivery → Exploitation → Installation → C2 → Actions on Objectives</code>。<strong>有意思的是,后六步公司都有产品在卖</strong>——EDR 管 4/5/6,SIEM 管 6/7,DLP 管 7。<strong>只有第 1 步几乎没有&quot;成熟商业产品挡得住&quot;</strong>。原因很简单:侦察基本不碰你的资产,大多数动作发生在你看不见的地方——查证书透明度日志、查 GitHub、查 Shodan 历史快照。<strong>你拦不了 attacker 在百度搜你公司的人。</strong></p><h3 id="_1-2-防御方的三个认知陷阱" tabindex="-1">1.2 防御方的三个认知陷阱 <a class="header-anchor" href="#_1-2-防御方的三个认知陷阱" aria-label="Permalink to &quot;1.2 防御方的三个认知陷阱&quot;">​</a></h3><p><strong>「我们外网只暴露一个网关」</strong>——错。一个中等规模公司,真实的对外资产通常是 IT 自己以为的 5-10 倍:测试环境忘了关、子公司继承过来的老系统、第三方 SaaS 集成进来的回调端口、CI 临时开的 debug port、被收购公司留下的 marketing 站点。</p><p><strong>「攻击者只会扫 80/443」</strong>——错。Shodan / Censys 把全 65535 个端口持续扫描,数据公开免费查。8080 端口的 Jenkins、9200 的 Elasticsearch、6379 的 Redis,三秒检索到。</p><p><strong>「没有公开链接的 URL 别人找不到」</strong>——错。子域名通过证书透明度日志(CT log)100% 可枚举——只要申请过 Let&#39;s Encrypt 证书,域名就在 crt.sh 永久公开,删都删不掉。</p><h3 id="_1-3-攻击者侦察的两条目标线" tabindex="-1">1.3 攻击者侦察的两条目标线 <a class="header-anchor" href="#_1-3-攻击者侦察的两条目标线" aria-label="Permalink to &quot;1.3 攻击者侦察的两条目标线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>目标</th><th>攻击者想知道什么</th><th>用到的技术</th></tr></thead><tbody><tr><td>资产线</td><td>公司有哪些 IP / 域名 / 服务</td><td>子域名枚举、Shodan、CT 日志</td></tr><tr><td>人线</td><td>谁有权限、邮箱格式、技术栈</td><td>LinkedIn、GitHub、招聘网站</td></tr></tbody></table><p>资产线找的是「<strong>机器入口</strong>」(漏洞利用),人线找的是「<strong>人员入口</strong>」(钓鱼)。<strong>真实事故里两条线常常合二为一</strong>——先在 LinkedIn 找到目标公司 SRE,看他 GitHub 提交过什么仓库,然后在 commit history 里翻出他不小心提交过的 <code>.aws/credentials</code>。</p><h3 id="_1-4-防御方的真正解法-先摸自己" tabindex="-1">1.4 防御方的真正解法:先摸自己 <a class="header-anchor" href="#_1-4-防御方的真正解法-先摸自己" aria-label="Permalink to &quot;1.4 防御方的真正解法:先摸自己&quot;">​</a></h3><p>防御侦察 ≠ 阻止扫描(挡不住),= 站在外面看自己的攻击面 + 持续比对清单。这就是 <strong>EASM(External Attack Surface Management)</strong> 的本质——把&quot;自己公司&quot;当作攻击者扫一遍,然后<strong>每天 diff</strong>:今天比昨天多了哪个域名 / 端口 / 证书?<strong>所有&quot;未授权暴露&quot;都应该在你日历最早提醒里,而不是在 attacker 的 Shodan 收藏夹里</strong>。</p><hr><h2 id="二、osint-开源情报里能挖出多少东西" tabindex="-1">二、OSINT:开源情报里能挖出多少东西 <a class="header-anchor" href="#二、osint-开源情报里能挖出多少东西" aria-label="Permalink to &quot;二、OSINT:开源情报里能挖出多少东西&quot;">​</a></h2><h3 id="_2-1-osint-是什么" tabindex="-1">2.1 OSINT 是什么 <a class="header-anchor" href="#_2-1-osint-是什么" aria-label="Permalink to &quot;2.1 OSINT 是什么&quot;">​</a></h3><p><strong>OSINT(Open Source Intelligence)</strong> = 所有从「公开渠道」能拿到的关于目标的信息。<strong>关键字是「公开」</strong>——不入侵,不绕过权限,<strong>全部是合法可查的信息,但合起来威力惊人</strong>。</p><p>OSINT 的精髓不是某个单一来源,<strong>是「拼图」</strong>——单看一个 LinkedIn 头衔啥也不是,加上 GitHub 邮箱、加上招聘 JD、加上 SEC 公告,就能拼出&quot;这家公司有 8 个 SRE,主用 AWS + K8s,正在招 Rust 工程师所以可能在重写网关,CTO 周末刚推了一个 fork 的开源仓库……&quot;——<strong>所有这些都不需要任何权限</strong>。</p><h3 id="_2-2-公开信息里最值钱的几类" tabindex="-1">2.2 公开信息里最值钱的几类 <a class="header-anchor" href="#_2-2-公开信息里最值钱的几类" aria-label="Permalink to &quot;2.2 公开信息里最值钱的几类&quot;">​</a></h3><p><strong>公司层面</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 官网技术博客 / 招聘 JD     → 技术栈、版本号</span></span>
<span class="line"><span>- SEC / 工商公告              → 子公司、收购历史(攻击面延伸)</span></span>
<span class="line"><span>- DNS WHOIS                  → 域名注册人邮箱(钓鱼目标)</span></span>
<span class="line"><span>- 招标 / 政府采购             → 用了哪家 IT 厂商、什么型号设备</span></span>
<span class="line"><span>- Wayback Machine            → 老版本网站、删掉的页面、临时链接</span></span></code></pre></div><p><strong>人员层面</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- LinkedIn                   → 员工列表 + 技术栈</span></span>
<span class="line"><span>- GitHub                     → 代码、commit 邮箱、误推的密钥</span></span>
<span class="line"><span>- 推特 / 知乎 / 个人博客       → 在用什么工具、抱怨过什么 bug</span></span>
<span class="line"><span>- 简历投递平台                 → 离职员工(防御松懈、知道老密码)</span></span></code></pre></div><h3 id="_2-3-github-泄露-osint-的重灾区" tabindex="-1">2.3 GitHub 泄露:OSINT 的重灾区 <a class="header-anchor" href="#_2-3-github-泄露-osint-的重灾区" aria-label="Permalink to &quot;2.3 GitHub 泄露:OSINT 的重灾区&quot;">​</a></h3><p>工程师最常制造的 OSINT 灾难:<code>git commit + push</code> 之后才发现 <code>config.json</code> 里有 <code>AWS_ACCESS_KEY_ID</code>。哪怕 5 分钟后 force push 删除——<strong>没用</strong>。GitHub 的 commit 历史在 fork、在镜像站、在 GHArchive,<strong>永久可查</strong>。GitGuardian 2024 年报告显示,公开 GitHub 上每天新增的密钥泄露 <strong>23,000+</strong>——99% 是工程师&quot;不小心 push 上去&quot;。自查方式:<strong>trufflehog / gitleaks 扫全 org 历史</strong>;GitHub 搜 <code>@company.com</code> 看哪些 commit 邮箱泄露;org 设置里检查内部仓库是否被误公开。</p><h3 id="_2-4-linkedin-与-邮件格式枚举" tabindex="-1">2.4 LinkedIn 与&quot;邮件格式枚举&quot; <a class="header-anchor" href="#_2-4-linkedin-与-邮件格式枚举" aria-label="Permalink to &quot;2.4 LinkedIn 与&quot;邮件格式枚举&quot;&quot;">​</a></h3><p>LinkedIn 是钓鱼的金矿——但<strong>真正危险的是邮件格式</strong>。LinkedIn 搜 &quot;John Smith - SRE at ACME&quot;,再到 GitHub 公开 commit 看到 <code>john.smith@acme.com</code>,就能推断 ACME 的邮件格式是 <code>{first}.{last}@acme.com</code>——1000 人公司的邮件列表瞬间生成,定向钓鱼起点就有了。</p><p><strong>防御</strong>:这是无法&quot;挡&quot;的(LinkedIn / GitHub 都是合法公开),只能<strong>反向利用</strong>——内部红队定期向员工发模拟钓鱼测试点击率;高价值账户(财务、IT 管理员)默认 MFA + 硬件 key。</p><hr><h2 id="三、子域名枚举-资产边界的发现" tabindex="-1">三、子域名枚举:资产边界的发现 <a class="header-anchor" href="#三、子域名枚举-资产边界的发现" aria-label="Permalink to &quot;三、子域名枚举:资产边界的发现&quot;">​</a></h2><h3 id="_3-1-为什么子域名是首要目标" tabindex="-1">3.1 为什么子域名是首要目标 <a class="header-anchor" href="#_3-1-为什么子域名是首要目标" aria-label="Permalink to &quot;3.1 为什么子域名是首要目标&quot;">​</a></h3><p>主站 <code>acme.com</code> 通常防护严密——CDN、WAF、定期渗透。<strong>但 <code>dev.acme.com</code>、<code>old-billing.acme.com</code>、<code>internal-tools.acme.com</code> 通常不是</strong>——这些是 attacker 的真正入口。<strong>一句业界格言</strong>:</p><blockquote><p>&quot;Subdomain takeover is the new SQL injection.&quot; —— bug bounty 报告高频项</p></blockquote><p>子域名越多,你能控制的边界越长,<strong>忘记下线的就越多</strong>。</p><h3 id="_3-2-枚举的三种路线" tabindex="-1">3.2 枚举的三种路线 <a class="header-anchor" href="#_3-2-枚举的三种路线" aria-label="Permalink to &quot;3.2 枚举的三种路线&quot;">​</a></h3><p><strong>路线 1:DNS 暴力枚举</strong>——拿一个常见前缀字典(<code>dev</code>、<code>stage</code>、<code>test</code>、<code>admin</code>、<code>mail</code>、<code>api</code>...)拼接到目标域名,逐个 DNS 查询,看哪个有 A 记录。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 字典里几千个常见子域前缀,逐个查</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sub </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stage</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">do</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $sub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.example.com</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">done</span></span></code></pre></div><p>便宜、可控,<strong>但漏的多</strong>——<code>prod-blue-2024-internal.acme.com</code> 这种字典里没有的猜不到。</p><p><strong>路线 2:证书透明度日志(CT log)</strong>——这是<strong>最可靠</strong>的一条路。从 2018 年起,所有 CA 签发的证书必须提交到公开的 CT 日志,任何人都能查:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># crt.sh 是最常用的查询入口(只看,不要去搞别人的资产)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://crt.sh/?q=%25.example.com&amp;output=json&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.[].name_value&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span></span></code></pre></div><p><strong>只要你域名申请过 HTTPS 证书,就在公开日志里</strong>——这意味着即便你设了内网 DNS、没对外解析,<strong>只要证书签发了,域名就被记录</strong>。<strong>很多公司因此暴露了内部子域</strong>——典型例子:<code>vpn-internal.company.com</code> 申请了 Let&#39;s Encrypt 证书,域名永久公开。</p><p><strong>路线 3:第三方聚合 API</strong>——把 CT log、Passive DNS(被动 DNS 数据库)、第三方扫描数据等聚合起来:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># subfinder / amass 是常用工具(只用于自己授权域)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">subfinder</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -silent</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">amass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enum</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -passive</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre></div><p><strong><code>-passive</code></strong>:只查公开数据库,不向目标发包,<strong>防御方完全察觉不到</strong>。这是侦察阶段最常用的姿势——<strong>不打草惊蛇</strong>。</p><h3 id="_3-3-子域名接管-被遗忘的资产怎么变成攻击入口" tabindex="-1">3.3 子域名接管:被遗忘的资产怎么变成攻击入口 <a class="header-anchor" href="#_3-3-子域名接管-被遗忘的资产怎么变成攻击入口" aria-label="Permalink to &quot;3.3 子域名接管:被遗忘的资产怎么变成攻击入口&quot;">​</a></h3><p><strong>Subdomain Takeover</strong> 的经典场景:你曾经把 <code>promo.example.com</code> 用 CNAME 指向 Heroku 的 <code>my-app.herokuapp.com</code>,活动结束后把 Heroku app 删了,<strong>但忘记了在 DNS 里删 CNAME</strong>。攻击者重新注册一个叫 <code>my-app</code> 的 Heroku app,<strong><code>promo.example.com</code> 就解析到他控制的页面</strong>——他可以用你的子域发钓鱼、偷你的 Cookie(同根域)。<strong>根因</strong>:DNS 记录和实际服务生命周期不一致。<strong>修复</strong>:每次下线服务时,DNS 清理是 checklist 强制项;定期用 dnstwist / subjack 扫自己的 dangling 记录。</p><h3 id="_3-4-防御侧-把自己的子域当作资产" tabindex="-1">3.4 防御侧:把自己的子域当作资产 <a class="header-anchor" href="#_3-4-防御侧-把自己的子域当作资产" aria-label="Permalink to &quot;3.4 防御侧:把自己的子域当作资产&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>持续运行(每天):</span></span>
<span class="line"><span>1. subfinder -d company.com 拿全量子域清单</span></span>
<span class="line"><span>2. 与昨天清单 diff</span></span>
<span class="line"><span>3. 新增子域 → 自动告警(谁起的?有没有备案?)</span></span>
<span class="line"><span>4. 消失子域 → 检查 DNS 是否清理干净</span></span></code></pre></div><p><strong>这就是 EASM 的最小可用版本</strong>。商业产品(Censys ASM、Microsoft Defender EASM)做得更全,但「<strong>每天 diff 一次子域清单</strong>」自己写脚本一小时就能搞定,优先级远高于买产品。</p><hr><h2 id="四、端口扫描-nmap-的三种扫描机制" tabindex="-1">四、端口扫描:nmap 的三种扫描机制 <a class="header-anchor" href="#四、端口扫描-nmap-的三种扫描机制" aria-label="Permalink to &quot;四、端口扫描:nmap 的三种扫描机制&quot;">​</a></h2><h3 id="_4-1-主动侦察的边界" tabindex="-1">4.1 主动侦察的边界 <a class="header-anchor" href="#_4-1-主动侦察的边界" aria-label="Permalink to &quot;4.1 主动侦察的边界&quot;">​</a></h3><p>子域名找完,下一步是「哪些 IP 开了什么端口」。<strong>这一步从被动转主动</strong>——发包到目标,目标的防火墙/IDS 能看见。<strong>所以仅在你拥有授权的资产上做</strong>(自己的 IP、租用的 VPS、CTF 靶机)。</p><p><code>nmap</code> 是事实标准,30 年来没变过。讲清三种最核心的扫描类型就够:</p><h3 id="_4-2-tcp-connect-扫描-st" tabindex="-1">4.2 TCP Connect 扫描(<code>-sT</code>) <a class="header-anchor" href="#_4-2-tcp-connect-扫描-st" aria-label="Permalink to &quot;4.2 TCP Connect 扫描(\`-sT\`)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在自己服务器上扫自己</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span></span></code></pre></div><p>完整的 TCP 三次握手:SYN → SYN-ACK → ACK,然后立即断开。<strong>优点</strong>:不要 root,任何用户都能跑(普通 connect 系统调用);<strong>缺点</strong>:每个端口都进系统的连接表,<strong>目标的应用层日志会看到一次&quot;短暂连接&quot;</strong>——隐蔽性差。</p><h3 id="_4-3-syn-半开扫描-ss-默认" tabindex="-1">4.3 SYN 半开扫描(<code>-sS</code>,默认) <a class="header-anchor" href="#_4-3-syn-半开扫描-ss-默认" aria-label="Permalink to &quot;4.3 SYN 半开扫描(\`-sS\`,默认)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.1.0/24</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 必须 root</span></span></code></pre></div><p>只发 SYN,<strong>收到 SYN-ACK 后不发 ACK,直接 RST 关闭</strong>——握手没完成,<strong>应用层根本没意识到有人来过</strong>。被称为 &quot;stealth scan&quot;,<strong>这是 nmap 默认模式</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  Client             Server</span></span>
<span class="line"><span>                    │                  │</span></span>
<span class="line"><span>                    │──── SYN ────────&gt;│   (打这个端口)</span></span>
<span class="line"><span>                    │&lt;── SYN/ACK ──────│   (开着)</span></span>
<span class="line"><span>                    │──── RST ────────&gt;│   (不握手,直接关)</span></span>
<span class="line"><span>                    │                  │</span></span>
<span class="line"><span>端口 open:server 回 SYN/ACK</span></span>
<span class="line"><span>端口 closed:server 回 RST</span></span>
<span class="line"><span>端口 filtered:server 没回(被防火墙挡了)</span></span></code></pre></div><p><strong>防御视角</strong>:SYN 半连接在内核 TCP 栈是可见的,<strong>只是应用层看不见</strong>——netstat、conntrack 表里能查到,Linux 的 SYN backlog 满了还会告警。<strong>所以 SYN 扫描不是&quot;隐身&quot;,是&quot;应用层隐身&quot;</strong>。</p><h3 id="_4-4-udp-扫描-su" tabindex="-1">4.4 UDP 扫描(<code>-sU</code>) <a class="header-anchor" href="#_4-4-udp-扫描-su" aria-label="Permalink to &quot;4.4 UDP 扫描(\`-sU\`)&quot;">​</a></h3><p>UDP 是无连接的,<strong>扫起来异常痛苦</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- UDP 端口&quot;开&quot;的标志是 &quot;应用回了 UDP 响应&quot;</span></span>
<span class="line"><span>- 但很多应用收到空包根本不回(比如 DNS 收到 &quot;AAAA AAAA&quot; 不解析)</span></span>
<span class="line"><span>- 端口&quot;关闭&quot;的标志是 ICMP &quot;Port Unreachable&quot;</span></span>
<span class="line"><span>- 但 ICMP 响应被 Linux 默认限速到 1/秒</span></span>
<span class="line"><span>- 所以扫 65535 个 UDP 端口要 18+ 小时</span></span></code></pre></div><p><strong>实战里很少全段 UDP 扫描</strong>——一般只扫 50 个常见 UDP 端口(53 DNS、123 NTP、161 SNMP、500 IKE、1900 SSDP、3389 RDP-UDP、5060 SIP、11211 Memcached……),够了。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sU</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --top-ports</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 50</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.1.10</span></span></code></pre></div><p><strong>防御视角</strong>:UDP 暴露的高危服务比 TCP 还危险——<strong>反射放大攻击</strong>全靠 UDP 服务(memcached 放大 51000 倍、NTP monlist 放大 556 倍)。<strong>最起码的规则</strong>:云上安全组里 UDP 默认全关,只按需打开。</p><h3 id="_4-5-nmap-常用参数-扫自己用" tabindex="-1">4.5 nmap 常用参数(扫自己用) <a class="header-anchor" href="#_4-5-nmap-常用参数-扫自己用" aria-label="Permalink to &quot;4.5 nmap 常用参数(扫自己用)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sV</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --top-ports</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 自己的IP</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -sS    SYN 半开扫描</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -sV    探测服务版本(banner grab)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -O     猜操作系统(TCP/IP fingerprint)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -p-    扫全 65535 端口</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># --top-ports 1000  只扫最常见 1000 端口(快 60 倍)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -T4    时序模板(0=极慢,5=极快,4 是常用平衡)</span></span></code></pre></div><p><strong>注意</strong>:扫越快越容易触发对方限速 / 封 IP——攻击者实战会用 <code>-T1</code>(慢扫,几小时一个 IP),避开 IDS;防御方写规则也要意识到&quot;慢扫不会触发阈值告警&quot;。</p><h3 id="_4-6-工程师视角-扫描结果怎么读" tabindex="-1">4.6 工程师视角:扫描结果怎么读 <a class="header-anchor" href="#_4-6-工程师视角-扫描结果怎么读" aria-label="Permalink to &quot;4.6 工程师视角:扫描结果怎么读&quot;">​</a></h3><p>nmap 输出三类结果:<strong>open / closed / filtered</strong>:</p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th><th>攻击者怎么看</th></tr></thead><tbody><tr><td>open</td><td>应用回应了</td><td>进一步查指纹、找 CVE</td></tr><tr><td>closed</td><td>端口没监听但 IP 在线</td><td>跳过</td></tr><tr><td>filtered</td><td>防火墙挡了,看不见</td><td>标记&quot;可能开但拦了&quot;,换路线</td></tr></tbody></table><p><strong>filtered 多 ≠ 安全</strong>——只意味着&quot;扫描者没法直接看到&quot;。真实攻击者会换 IP、绕代理、走 IPv6、找 VPN 后面的入口。<strong>绝对不要把&quot;防火墙挡住扫描&quot;等同于&quot;端口安全&quot;</strong>。</p><hr><h2 id="五、服务指纹-banner-grab、ja3-ja4、http-头特征" tabindex="-1">五、服务指纹:Banner Grab、JA3/JA4、HTTP 头特征 <a class="header-anchor" href="#五、服务指纹-banner-grab、ja3-ja4、http-头特征" aria-label="Permalink to &quot;五、服务指纹:Banner Grab、JA3/JA4、HTTP 头特征&quot;">​</a></h2><h3 id="_5-1-端口开了之后-它是什么" tabindex="-1">5.1 端口开了之后:它是什么 <a class="header-anchor" href="#_5-1-端口开了之后-它是什么" aria-label="Permalink to &quot;5.1 端口开了之后:它是什么&quot;">​</a></h3><p><code>nmap -sV</code> 做的事是「<strong>banner grab</strong>」——TCP 握手成功后,有些服务会主动发欢迎信息:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 自己服务器</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SSH-2.0-OpenSSH_8.9p1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Ubuntu-3ubuntu0.4</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 自己服务器</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 25</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">220</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mail.example.com</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ESMTP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Postfix</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (Ubuntu)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 自己服务器</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">220</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (vsFTPd </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3.0.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p><strong>Banner 暴露了三个关键信息</strong>:服务类型、版本号、运行平台。<strong>版本号是关键</strong>——<code>OpenSSH_8.9p1</code> 可以直接到 CVE 数据库查:这个版本有没有未修复漏洞?</p><h3 id="_5-2-隐藏-banner-不是真正的防御" tabindex="-1">5.2 隐藏 banner 不是真正的防御 <a class="header-anchor" href="#_5-2-隐藏-banner-不是真正的防御" aria-label="Permalink to &quot;5.2 隐藏 banner 不是真正的防御&quot;">​</a></h3><p>工程师常见的&quot;修法&quot;:配置 <code>nginx.conf</code> 加 <code>server_tokens off;</code>,改 SSH banner 假装是别的版本。<strong>这只挡得住自动扫描脚本里的版本匹配,挡不住真正的攻击者</strong>——他们会发特定的协议帧,根据&quot;对方怎么响应非标输入&quot;反推真实版本(被动指纹识别 / passive fingerprinting)。</p><p><strong>真正的防御不是&quot;藏版本&quot;,是&quot;及时打补丁&quot;</strong>。<code>server_tokens off</code> 该开还是开,但<strong>别误以为这就安全了</strong>。</p><h3 id="_5-3-tls-指纹-ja3-与-ja4" tabindex="-1">5.3 TLS 指纹:JA3 与 JA4 <a class="header-anchor" href="#_5-3-tls-指纹-ja3-与-ja4" aria-label="Permalink to &quot;5.3 TLS 指纹:JA3 与 JA4&quot;">​</a></h3><p><strong>JA3</strong> 由 Salesforce 在 2017 年开源——把 TLS ClientHello 的字段(version、cipher suites、extensions、椭圆曲线、压缩方法)按固定顺序拼起来做 MD5,得到 32 字节&quot;客户端指纹&quot;。<strong>为什么这个有用</strong>:Chrome 的 JA3 是一个固定值、Firefox 是另一个、Python <code>requests</code> 是第三个——<strong>一个伪造 User-Agent 的爬虫,JA3 会暴露它</strong>。</p><p><strong>JA4</strong>(2023)是 JA4+ 套件的一部分,<strong>比 JA3 更稳健</strong>——不再做 MD5(可碰撞),改用按字段切片拼接的明文格式,可读、可比对、对 QUIC 也适用。<strong>现代 WAF / CDN 大量用 JA3/JA4 识别&quot;非正常浏览器&quot;</strong>(Cloudflare、Akamai 都集成了)。攻防双向:攻击者用 <a href="https://github.com/lwthiker/curl-impersonate" target="_blank" rel="noreferrer">curl-impersonate</a> 把 curl 的 JA3 改成 Chrome 的样子绕过检测;防御者把 JA3/JA4 + UA + 行为综合打分,而不是单点判断。</p><h3 id="_5-4-http-头特征" tabindex="-1">5.4 HTTP 头特征 <a class="header-anchor" href="#_5-4-http-头特征" aria-label="Permalink to &quot;5.4 HTTP 头特征&quot;">​</a></h3><p>HTTP 服务的指纹除了 <code>Server</code> 头,还有一堆&quot;间接指纹&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Server: nginx/1.24.0          ← 显式</span></span>
<span class="line"><span>X-Powered-By: PHP/8.2.1       ← 显式</span></span>
<span class="line"><span>X-AspNet-Version: 4.0.30319   ← 显式</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Set-Cookie: PHPSESSID=...     ← 隐式(PHP)</span></span>
<span class="line"><span>Set-Cookie: JSESSIONID=...    ← 隐式(Java)</span></span>
<span class="line"><span>Set-Cookie: .ASPXAUTH=...     ← 隐式(.NET)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ETag 格式 / Date 头顺序 / 错误页 HTML 结构 ← 间接</span></span></code></pre></div><p><strong>清理显式头容易,清理间接指纹几乎不可能</strong>——返回的 404 页面 HTML 长什么样,<code>Date</code> 头放在 <code>Server</code> 头前面还是后面,<strong>这些都被 fingerprint 工具拿来识别</strong>。</p><hr><h2 id="六、web-指纹-whatweb-wappalyzer-favicon-hash" tabindex="-1">六、Web 指纹:WhatWeb / Wappalyzer / Favicon Hash <a class="header-anchor" href="#六、web-指纹-whatweb-wappalyzer-favicon-hash" aria-label="Permalink to &quot;六、Web 指纹:WhatWeb / Wappalyzer / Favicon Hash&quot;">​</a></h2><h3 id="_6-1-应用层指纹的目标" tabindex="-1">6.1 应用层指纹的目标 <a class="header-anchor" href="#_6-1-应用层指纹的目标" aria-label="Permalink to &quot;6.1 应用层指纹的目标&quot;">​</a></h3><p>到这层不再问&quot;是什么 Web 服务器&quot;,而是问&quot;<strong>跑的什么应用</strong>&quot;:WordPress?Drupal?Jenkins?GitLab?如果是 WordPress,<strong>装了哪些插件</strong>?这些信息决定了 attacker 下一步去 CVE 库里搜什么。</p><h3 id="_6-2-whatweb-wappalyzer" tabindex="-1">6.2 WhatWeb / Wappalyzer <a class="header-anchor" href="#_6-2-whatweb-wappalyzer" aria-label="Permalink to &quot;6.2 WhatWeb / Wappalyzer&quot;">​</a></h3><p><code>whatweb</code> 是 Ruby 写的命令行工具,内置 1800+ 个签名:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whatweb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://自己网站.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出示例</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://example.com</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [200 </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">OK]</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Country[US],</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">HTTPServer[nginx],</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> JQuery[3.6.0],</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Open-Graph-Protocol,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> WordPress[6.4.2],</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">X-Frame-Options[SAMEORIGIN]</span></span></code></pre></div><p><code>Wappalyzer</code> 是浏览器插件(也有 CLI),覆盖更广——不光识别 Web 框架,还识别 CDN、分析工具、广告 SDK、CMS 等。</p><p><strong>指纹的判定方式</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- HTML 里的 &lt;meta name=&quot;generator&quot; content=&quot;WordPress 6.4.2&quot;&gt;</span></span>
<span class="line"><span>- HTTP 头 X-Generator</span></span>
<span class="line"><span>- 特定 URL 路径(/wp-admin/、/administrator/)</span></span>
<span class="line"><span>- 特定 JS 文件名(jquery.js、react.production.min.js)</span></span>
<span class="line"><span>- 特定 CSS 类名(elementor-、wp-block-)</span></span></code></pre></div><p><strong>修复思路</strong>:<strong>不要试图全删</strong>——删了功能就坏了。<strong>关键是&quot;被识别 = 必须立即知道有 CVE 要打补丁&quot;</strong>。</p><h3 id="_6-3-favicon-hash-被低估的指纹" tabindex="-1">6.3 Favicon Hash:被低估的指纹 <a class="header-anchor" href="#_6-3-favicon-hash-被低估的指纹" aria-label="Permalink to &quot;6.3 Favicon Hash:被低估的指纹&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 算法极简</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hashlib, requests</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">favicon </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> requests.get(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://example.com/favicon.ico&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).content</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(hashlib.md5(favicon).hexdigest())   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或 mmh3</span></span></code></pre></div><p>为什么这玩意儿重要——<strong>很多内部管理后台用默认 favicon</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- Jenkins 默认 favicon → MD5 是某个固定值</span></span>
<span class="line"><span>- GitLab 默认 favicon → 另一个固定值</span></span>
<span class="line"><span>- Grafana 默认 favicon → 第三个固定值</span></span></code></pre></div><p><strong>Shodan 支持 <code>http.favicon.hash</code> 搜索</strong>:一行查询就能列出全球所有&quot;暴露在公网 + 用默认 favicon 的 Jenkins 实例&quot;。<strong>这就是为什么&quot;换个 favicon&quot;成了被忽视的安全建议</strong>——能让你脱离全网扫描器的&quot;批量目标列表&quot;。</p><h3 id="_6-4-工程师的-favicon-清单" tabindex="-1">6.4 工程师的 favicon 清单 <a class="header-anchor" href="#_6-4-工程师的-favicon-清单" aria-label="Permalink to &quot;6.4 工程师的 favicon 清单&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ 把默认 favicon 替换成公司自己的</span></span>
<span class="line"><span>✓ 内部后台(Jenkins / Grafana / Kibana)的 favicon 也换掉</span></span>
<span class="line"><span>✓ 错误页(404 / 500)别用框架默认页(自己写一个)</span></span>
<span class="line"><span>✓ HTTP 头别带框架自己加的 X-Powered-By</span></span></code></pre></div><p>这一组细节单看每条都是小事,<strong>合起来能让你的资产&quot;脱离全网批量目标&quot;</strong>——攻击者扫到的 100 万个 Jenkins 里,你这一个不在那个列表上。</p><hr><h2 id="七、shodan-censys-fofa-被动-osint-的工业化" tabindex="-1">七、Shodan / Censys / FOFA:被动 OSINT 的工业化 <a class="header-anchor" href="#七、shodan-censys-fofa-被动-osint-的工业化" aria-label="Permalink to &quot;七、Shodan / Censys / FOFA:被动 OSINT 的工业化&quot;">​</a></h2><h3 id="_7-1-它们是什么" tabindex="-1">7.1 它们是什么 <a class="header-anchor" href="#_7-1-它们是什么" aria-label="Permalink to &quot;7.1 它们是什么&quot;">​</a></h3><p><strong>Shodan</strong>(2009 创立)和 <strong>Censys</strong>(2015,密歇根大学出身)是「<strong>互联网扫描数据库</strong>」——它们自己 7x24 小时扫描全 IPv4 地址(所有端口、所有协议),结果存下来供任意查询。攻击者视角:<strong>不用自己扫,几秒查到结果</strong>;防御者视角:<strong>你的资产暴露多少,他们已经替你扫好了</strong>。<strong>FOFA</strong>(白帽汇,中国)是国内同类,中国资产覆盖更细。</p><h3 id="_7-2-能查到什么-对你自己的资产" tabindex="-1">7.2 能查到什么(对你自己的资产) <a class="header-anchor" href="#_7-2-能查到什么-对你自己的资产" aria-label="Permalink to &quot;7.2 能查到什么(对你自己的资产)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>shodan search &#39;org:&quot;YOUR COMPANY&quot;&#39;              # 你公司所有暴露资产</span></span>
<span class="line"><span>shodan search &#39;ssl:&quot;yourdomain.com&quot;&#39;            # 用了你证书的 IP</span></span>
<span class="line"><span>shodan search &#39;http.favicon.hash:XXXX&#39;          # 用某 favicon 的所有 IP</span></span>
<span class="line"><span>shodan search &#39;product:Elasticsearch port:9200&#39; # 公网 ES(无认证)</span></span>
<span class="line"><span>shodan search &#39;product:Redis port:6379&#39;         # 公网 Redis(2018 勒索根因)</span></span></code></pre></div><p>每一条都是&quot;几秒钟拿到全球清单&quot;。<strong>这是为什么&quot;安全组默认拒绝、按需开放&quot;是黄金规则</strong>——只要你 6379 暴露过 10 分钟,Shodan 的爬虫就大概率扫到过,<strong>截图永远存档</strong>。</p><h3 id="_7-3-防御侧-shodan-monitor" tabindex="-1">7.3 防御侧:Shodan Monitor <a class="header-anchor" href="#_7-3-防御侧-shodan-monitor" aria-label="Permalink to &quot;7.3 防御侧:Shodan Monitor&quot;">​</a></h3><p>Shodan / Censys 都有 <strong>Monitor / ASM</strong> 模式——你订阅自己的 IP 段或域名,他们扫到任何新暴露(新端口、新证书、新软件版本)立刻给你告警。免费层够小公司用,付费层给中大公司做 API 自动化。国内还有 <strong>ZoomEye / Quake / BinaryEdge</strong>。<strong>主流选择</strong>:Shodan + Censys 主用,FOFA / ZoomEye 国内补充——一家覆盖不全,交叉查更稳。<strong>这是攻击者免费用的工具,防御方更应该用,而且要先于攻击者用</strong>。</p><hr><h2 id="八、防御视角-把侦察阶段堵住的工程实践" tabindex="-1">八、防御视角:把侦察阶段堵住的工程实践 <a class="header-anchor" href="#八、防御视角-把侦察阶段堵住的工程实践" aria-label="Permalink to &quot;八、防御视角:把侦察阶段堵住的工程实践&quot;">​</a></h2><h3 id="_8-1-easm-external-attack-surface-management-三件事" tabindex="-1">8.1 EASM(External Attack Surface Management)三件事 <a class="header-anchor" href="#_8-1-easm-external-attack-surface-management-三件事" aria-label="Permalink to &quot;8.1 EASM(External Attack Surface Management)三件事&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 发现(Discovery): 你不知道的资产被发现</span></span>
<span class="line"><span>2. 清单(Inventory):每个资产有 owner、用途、合规状态</span></span>
<span class="line"><span>3. 监控(Monitoring):资产变化每天 diff,异常告警</span></span></code></pre></div><p><strong>最常见的失败</strong>:有发现、无清单——扫出来 500 个子域,没人管&quot;哪个是哪个团队的、哪个该删&quot;。<strong>资产清单关键字段</strong>:域名/IP、owner、上线日期、业务用途、暴露端口、证书有效期、上次扫描时间。清单的本质:<strong>让每个资产有人负责、有下线时间、有 review 节奏</strong>。一旦没主了,下线。</p><h3 id="_8-2-资产清单从几个脚本起步" tabindex="-1">8.2 资产清单从几个脚本起步 <a class="header-anchor" href="#_8-2-资产清单从几个脚本起步" aria-label="Permalink to &quot;8.2 资产清单从几个脚本起步&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">subfinder</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> acme.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> today_subs.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 子域枚举</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> own_ip_range</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> today_ports.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 端口扫描(自己 IP)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shodan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;org:&quot;ACME&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> today_shodan.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Shodan 自查</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">diff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yesterday_subs.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> today_subs.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 每天 diff</span></span></code></pre></div><p><strong>每天跑一次,新增即告警</strong>。中等规模公司一周就能有清单雏形,远好于&quot;等买 EASM 产品的预算&quot;。</p><h3 id="_8-3-authorized-recon-常态化" tabindex="-1">8.3 Authorized Recon 常态化 <a class="header-anchor" href="#_8-3-authorized-recon-常态化" aria-label="Permalink to &quot;8.3 Authorized Recon 常态化&quot;">​</a></h3><p>&quot;<strong>红队扫自己</strong>&quot;应该是每个团队的常规操作——不是一年一次的渗透测试,<strong>是每周或每天的自检</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开发环境是否对外?          (默认应该全关)</span></span>
<span class="line"><span>新上线的接口有没有走 SSO?  (匿名访问应该 403)</span></span>
<span class="line"><span>新签发的证书属于谁?        (Slack 通知到 owner)</span></span>
<span class="line"><span>有没有 dangling DNS?       (subjack 扫)</span></span>
<span class="line"><span>GitHub 公开仓库有没有泄露? (trufflehog 跑全公司 org)</span></span></code></pre></div><p><strong>做这些不需要昂贵工具,需要的是&quot;把这些步骤纳入 CI/CD 与定期任务&quot;</strong>——这是 EASM 的&quot;工程化&quot;,<strong>比买产品本身更重要</strong>。</p><hr><h2 id="九、真实事故-capital-one-是怎么从-侦察-被入手的" tabindex="-1">九、真实事故:Capital One 是怎么从&quot;侦察&quot;被入手的 <a class="header-anchor" href="#九、真实事故-capital-one-是怎么从-侦察-被入手的" aria-label="Permalink to &quot;九、真实事故:Capital One 是怎么从&quot;侦察&quot;被入手的&quot;">​</a></h2><p>2019 年的 Capital One 数据泄露(1 亿美国信用卡用户)是侦察阶段被打穿的教科书案例:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 攻击者通过 Shodan / 子域扫描,找到一个错配的 WAF(ModSecurity)</span></span>
<span class="line"><span>   该 WAF 实例挂着一个 IAM role,可调 AWS 服务</span></span>
<span class="line"><span>2. WAF 配置错误允许接收任意来源的 SSRF 请求</span></span>
<span class="line"><span>3. 攻击者从外部发请求 → WAF 转发 → AWS 元数据 169.254.169.254</span></span>
<span class="line"><span>4. 拿到 WAF 实例的 IAM credentials</span></span>
<span class="line"><span>5. 用这个 credential 列 S3 bucket,下载用户数据</span></span></code></pre></div><p><strong>侦察阶段的关键点</strong>:攻击者没有任何&quot;高级 0day&quot;,<strong>只是发现了一个错配的 WAF 实例</strong>;这个 WAF 的暴露本来在资产清单里也许根本不显眼,但因为 IAM role 权限过大,<strong>单点错配把 1 亿用户拖下水</strong>。事后 Capital One 加了两件事:<strong>资产清单 + 持续扫描</strong>(每个对外资产 IAM role 全 review);<strong>IMDSv2 强制</strong>(SSRF 拿不到 metadata)。<strong>真正的攻击不靠 0day,靠&quot;你以为没人会注意到的那台机器&quot;</strong>——它在攻击者眼里是高亮的,因为它<strong>存在于 Shodan 但不存在于你的清单</strong>。</p><hr><h2 id="十、上线前外部侦察自检表" tabindex="-1">十、上线前外部侦察自检表 <a class="header-anchor" href="#十、上线前外部侦察自检表" aria-label="Permalink to &quot;十、上线前外部侦察自检表&quot;">​</a></h2><p>每次有新服务对外暴露之前,把这张表过一遍(不止安全团队,业务工程师上线前都该过):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ ] 资产登记</span></span>
<span class="line"><span>    [ ] 该资产已加入 EASM 清单(域名 / IP / 端口 / owner)</span></span>
<span class="line"><span>    [ ] 有明确的&quot;下线触发条件&quot;(项目结束 / 季度 review)</span></span>
<span class="line"><span>    [ ] DNS 记录与实际服务生命周期绑定</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[ ] 子域 / 证书</span></span>
<span class="line"><span>    [ ] 子域名命名不暴露技术栈(避免 jenkins.acme.com,改名 build-1.acme.com)</span></span>
<span class="line"><span>    [ ] 证书申请走内部 ACME 流程,自动续期</span></span>
<span class="line"><span>    [ ] 内部域名不申请公开 CA 证书(用私有 CA / 自签)</span></span>
<span class="line"><span>    [ ] dangling DNS 自查(subjack / dnstwist 周扫)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[ ] 端口</span></span>
<span class="line"><span>    [ ] 安全组默认拒绝,只放业务必需端口</span></span>
<span class="line"><span>    [ ] UDP 默认全关(除非业务确实需要)</span></span>
<span class="line"><span>    [ ] 管理端口(22 / 3389)不直接对公网(走 VPN / 跳板)</span></span>
<span class="line"><span>    [ ] 内部服务(Redis / ES / MQ)严禁对公网</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[ ] 指纹</span></span>
<span class="line"><span>    [ ] HTTP 服务:server_tokens off / X-Powered-By 移除</span></span>
<span class="line"><span>    [ ] 默认 favicon 已替换</span></span>
<span class="line"><span>    [ ] 错误页(404 / 500)不暴露框架特征</span></span>
<span class="line"><span>    [ ] 默认登录页 URL 已改名或加 IP allowlist</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[ ] OSINT 自检</span></span>
<span class="line"><span>    [ ] GitHub 公开仓库 trufflehog/gitleaks 全扫</span></span>
<span class="line"><span>    [ ] 公司域名邮箱在 haveibeenpwned 检查泄露</span></span>
<span class="line"><span>    [ ] LinkedIn / 招聘 JD 不要写&quot;我们用的 XX 版本&quot;</span></span>
<span class="line"><span>    [ ] Slack / 知乎 / 公开博客技术分享内部敏感细节脱敏</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[ ] 监控与告警</span></span>
<span class="line"><span>    [ ] Shodan / Censys Monitor 订阅自己的 IP 段 + 域名</span></span>
<span class="line"><span>    [ ] 每日 subfinder 扫子域,新增即告警</span></span>
<span class="line"><span>    [ ] CT 日志监控(crt.sh / Cert Spotter):新签证书 → 通知</span></span>
<span class="line"><span>    [ ] WAF / CDN 启用 JA3/JA4 异常检测</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[ ] 制度</span></span>
<span class="line"><span>    [ ] 每月一次&quot;自己扫自己&quot;红蓝演练(authorized recon)</span></span>
<span class="line"><span>    [ ] 资产清单 owner 字段每季度 review 一次</span></span>
<span class="line"><span>    [ ] 离职员工的 GitHub / 仓库权限即时清理</span></span></code></pre></div><p><strong>把这张表打印贴墙上,不是装饰</strong>——任何一项漏掉,都可能是下一个 Capital One。</p><hr><h2 id="十一、踩坑提醒" tabindex="-1">十一、踩坑提醒 <a class="header-anchor" href="#十一、踩坑提醒" aria-label="Permalink to &quot;十一、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为&quot;挡住扫描&quot;就安全</strong>——SYN 扫不留应用层日志,Shodan 数据已经永久公开。<strong>挡不住,只能先于攻击者摸自己</strong></li><li><strong>以为子域少</strong>——CT 日志一查通常多 5-10 倍。不查就以为&quot;我家就那几个域名&quot;</li><li><strong>以为没人会扫 IPv6</strong>——Shodan 在扫,Censys 在扫,IPv6 不是安全替代,只是命中率低</li><li><strong>以为 GitHub 删了 commit 就没事</strong>——history 永远存在,trufflehog 一扫一个准</li><li><strong>以为 favicon 不重要</strong>——<code>http.favicon.hash</code> 搜索把你纳入批量目标</li><li><strong>以为 banner 改了就安全</strong>——版本号能藏,但被动指纹藏不住,真正解法是打补丁</li><li><strong>以为 EASM 是产品</strong>——本质是流程。脚本能跑起来,比买不会用的产品有价值十倍</li><li><strong>以为侦察阶段没办法防</strong>——是。<strong>侦察是&quot;非对称&quot;的,防御方只能&quot;先自摸&quot;</strong></li><li><strong>以为业务工程师不用懂这一层</strong>——错,资产清单的 owner 就是业务工程师,<strong>你不参与,资产就会失控</strong></li><li><strong>以为&quot;内网&quot;是绝对安全的</strong>——VPN 接入、合作伙伴对接、收购的子公司,内外边界一直在被打穿</li></ol><hr><p>下一篇:<code>22-Web 渗透方法论.md</code>,讲清楚一个 Web 应用从&quot;侦察拿到目标 URL&quot;到&quot;找到第一个洞&quot;之间,真实红队是怎么走的——<strong>Burp Suite 的工作流(Proxy / Repeater / Intruder / Scanner)、手工 vs 自动化的边界、如何系统化地遍历一个 Web 应用的攻击面</strong>。讲完这一篇你应该能拿着 Burp 在自己搭的 DVWA / Juice Shop 上系统地把所有功能&quot;点一遍&quot;,而不是&quot;看到啥试啥的瞎打&quot;。</p>`,149)])])}const k=a(e,[["render",p]]);export{g as __pageData,k as default};
